IF NOT EXISTS (SELECT 1 FROM [dbo].[OTELLER] WHERE [OTEL_KODU]=N'ORK-SEED-007')
BEGIN
  DECLARE @p bigint=(SELECT TOP 1 id FROM PARTNER_DETAYLARI);
  DECLARE @u bigint=(SELECT TOP 1 id FROM KULLANICILAR WHERE [EPOSTA]=N'ork-demo-partner@otelturizm.local');
