  DECLARE @ilce bigint=(SELECT TOP 1 id FROM ILCELER WHERE [IL_ID]=@il ORDER BY [ID]);
  INSERT INTO [dbo].[OTELLER]([OTEL_KODU],[PARTNER_ID],[KULLANICI_ID],[OTEL_ADI],[OTEL_TURU],[OTEL_TIPI_ID],[YILDIZ_SAYISI],[ULKE],[SEHIR],[ILCE],[MAHALLE],[TAM_ADRES],[ULKE_ID],[SEHIR_ID],[ILCE_ID],[TELEFON_1],[EPOSTA],[REZERVASYON_TELEFONU],[SATIS_KONTAK_ADI],[SATIS_KONTAK_TELEFONU],[SATIS_KONTAK_EPOSTA],[CHECK_IN_SAATI],[CHECK_OUT_SAATI],[TOPLAM_ODA_SAYISI],[KISA_ACIKLAMA],[UZUN_ACIKLAMA],[VARSAYILAN_KOMISYON_ORANI],[ODEME_VADESI],[ODEME_YONTEMI],[FATURA_KESIM_TURU],[YAYIN_DURUMU],[ONAY_DURUMU],[ONAY_TARIHI],[OLUSTURULMA_TARIHI])
